<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">  digitalWrite</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">7</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, LOW);</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    // turn the BULB off by making the voltage LOW</span></span>
